import type MomentTimezoneIntl from '@lark/moment-timezone-intl';

function supportsDateStyle() {
  try {
    return !!(
      new Intl.DateTimeFormat(undefined, {
        dateStyle: 'short',
      }).resolvedOptions() as any
    ).dateStyle;
  } catch (_) {
    return false;
  }
}

/**
 * https://bugs.chromium.org/p/chromium/issues/detail?id=865351
 */
function hasChromeLt71Bug() {
  try {
    return (
      new Intl.DateTimeFormat('en', {
        hourCycle: 'h11',
        hour: 'numeric',
      }).formatToParts(0)[2].type !== 'dayPeriod'
    );
  } catch (_) {
    return false;
  }
}

/**
 * Node 14's version of Intl.DateTimeFormat does not throw
 * when dateStyle/timeStyle is used with other options.
 * This was fixed in newer V8 versions
 */
function hasUnthrownDateTimeStyleBug(): boolean {
  try {
    return !!new Intl.DateTimeFormat('en', {
      dateStyle: 'short',
      hour: 'numeric',
    }).format(new Date(0));
  } catch (_) {
    return false;
  }
}

/**
 * Credits: https://github.com/formatjs/formatjs/blob/d63e778d4900728d4b2f6710f11af683ed5c4bc7/packages/intl-datetimeformat/should-polyfill.ts
 */
function shouldPolyfill() {
  try {
    return (
      !('DateTimeFormat' in Intl) ||
      !('formatToParts' in Intl.DateTimeFormat.prototype) ||
      !('formatRange' in Intl.DateTimeFormat.prototype) ||
      hasChromeLt71Bug() ||
      hasUnthrownDateTimeStyleBug() ||
      !supportsDateStyle()
    );
  } catch (_) {
    return true;
  }
}

const mod: typeof MomentTimezoneIntl = shouldPolyfill()
  ? require('moment-timezone')
  : require('@lark/moment-timezone-intl');

export = mod;
